PROCEDURE ReliableMulticastReceive(message)
BEGIN
 // Maintain delivery sequence and seen messages
 delivered = FALSE

 // Check for duplicates
 IF message.seqNum IN receivedMessages THEN
 DISCARD message
 RETURN
 END IF

 // Store message
 ADD message.seqNum TO receivedMessages

 // Send acknowledgment to sender
 SEND ACK(message.seqNum) TO sender

 // Wait for agreement (from all others or timeout)
 acks = RECEIVE ACKS(timeout)

 // If agreement reached, deliver to application
 IF size(acks) >= (groupSize - 1) OR timeout THEN
 DELIVER message TO application
 END IF
END
